class Solution:
    def floor(self, n: float) -> int:
        if n < 0:
            return -int(-n + 0.5)
        else:
            return int(n + 0.5)


# Driver code
if __name__ == '__main__':
    ts = Solution()
    print(ts.floor(3.7))
    print(ts.floor(-2.9))
    print(ts.floor(-4))

