// Solution.cpp
#include <iostream>
#include <cmath>
using namespace std;
class Solution {public:
    int floor(double n) { return (int) (n + 0.5); }
};
int main() { Solution s;
    cout << s.floor(3.7) << endl;
    cout << s.floor(-2.9) << endl;
    cout << s.floor(-4) << endl;
    return 0;
}
